<?php
declare(strict_types=1);
namespace Zoosper\Admin\Controller;
use Zoosper\Auth\Service\AuthService; use Zoosper\Auth\Service\CsrfTokenManager; use Zoosper\Auth\Service\SessionGuard; use Zoosper\Core\Http\Request; use Zoosper\Core\Http\Response;
final readonly class LoginController { public function __construct(private AuthService $auth, private SessionGuard $guard, private CsrfTokenManager $csrf){} public function show(Request $r):Response{return $this->guard->user()?Response::redirect('/admin'):Response::html($this->form());} public function login(Request $r):Response{$f=$r->form(); if(!$this->csrf->isValid((string)($f['_csrf_token']??''))) return Response::html($this->form('Invalid security token.'),419); $u=$this->auth->authenticate((string)($f['email']??''),(string)($f['password']??'')); if($u===null)return Response::html($this->form('Invalid email or password.'),401); $this->guard->login($u); return Response::redirect('/admin');} public function logout(Request $r):Response{$f=$r->form(); if(!$this->csrf->isValid((string)($f['_csrf_token']??''))) return Response::html('Invalid security token.',419); $this->guard->logout(); return Response::redirect('/admin/login');} private function form(?string $error=null):string{$t=htmlspecialchars($this->csrf->token(),ENT_QUOTES,'UTF-8');$e=$error?'<p style="color:#b91c1c">'.htmlspecialchars($error,ENT_QUOTES,'UTF-8').'</p>':'';return '<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Zoosper Login</title><style>body{font-family:system-ui;margin:3rem}.card{max-width:420px;padding:2rem;border:1px solid #ddd;border-radius:16px}label{display:block;margin-top:1rem}input{width:100%;padding:.7rem}button{margin-top:1rem;padding:.7rem 1rem}</style></head><body><main class="card"><h1>Zoosper Admin</h1>'.$e.'<form method="post" action="/admin/login"><input type="hidden" name="_csrf_token" value="'.$t.'"><label>Email<input type="email" name="email" required></label><label>Password<input type="password" name="password" required></label><button>Log in</button></form></main></body></html>'; } }
